INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Aplica herramientas tecnológicas apropiadas, al ejecutar tareas específicas.', ARRAY['1.1. Selecciona el hardware de acuerdo con su uso y función, para utilizarlo adecuadamente y facilitar el trabajo.', '1.2. Utiliza aplicaciones de software de texto para tareas específicas, con eficiencia y velocidad.', '1.3. Representa información obtenida de fuentes externas, utilizando software de imágenes o presentaciones.']),
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Emplea información por medio de técnicas de investigación en la web de manera precisa, segura, legal y ética.', ARRAY['2.1. Selecciona técnicas de investigación de acuerdo con los requerimientos para elaborar diferentes documentos.', '2.2. Distingue sitios seguros y éticos para la obtención de información gráfica y textual.', '2.3. Demuestra valores éticos al hacer uso de la información y respeta los derechos de autor.']),
('Segundo Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Utiliza recursos tecnológicos colaborativos e interactivos en proyectos de investigación.', ARRAY['3.1. Selecciona tecnologías (programas, presentaciones, textos e imágenes) para facilitar el intercambio de comunicación.', '3.2. Utiliza diferentes programas para realizar presentaciones audiovisuales, contemplando las normas de presentación, contenido, diseño y uso bibliográfico.', '3.3. Comparte proyectos innovadores con diferentes usuarios a través de presentadores multimedia, en espacios educativos.']);
